-- In-session → Goal Setting scenario — Detailed Path
-- Stable keys map to fixed UUIDs in src/data/goalSettingDetailedPathFallback.ts

values (
  'a0000000-0000-4000-8000-000000000811',
  'a0000000-0000-4000-8000-000000000204',
  'Set Goals',
  'No prior personalized goals set and start of a new goal cycle.',
  'alternative'
)
on conflict (id) do update set
  service_scenario_id = excluded.service_scenario_id,
  name = excluded.name,
  description = excluded.description,
  path_type = excluded.path_type;

delete from public.cell_triggers where source_cell_id in (select id from public.cells where path_id = 'a0000000-0000-4000-8000-000000000811');
delete from public.cells where path_id = 'a0000000-0000-4000-8000-000000000811';
delete from public.layers where path_id = 'a0000000-0000-4000-8000-000000000811';
delete from public.path_steps where path_id = 'a0000000-0000-4000-8000-000000000811';

on conflict (id) do update set name = excluded.name, row_position = excluded.row_position, path_id = excluded.path_id;

on conflict (id) do update set name = excluded.name, service_scenario_id = excluded.service_scenario_id;

on conflict (path_id, step_id) do update set column_position = excluded.column_position;

on conflict (id) do update set path_id = excluded.path_id, layer_id = excluded.layer_id, step_id = excluded.step_id, content = excluded.content;

on conflict (id) do update set source_cell_id = excluded.source_cell_id, target_cell_id = excluded.target_cell_id;

update public.cells
set content = E'Dev Team\nDesign Team',
    description =
      'Dev Team builds the app and the Design Team creates the screens and flows relevant to this step. Both implement the findings from the research team into the app in their respective role.'
where id in (
  'a0000000-0000-4000-8000-0000001f0209',
  'a0000000-0000-4000-8000-0000001f0309',
  'a0000000-0000-4000-8000-0000001f0509',
  'a0000000-0000-4000-8000-0000001f0609',
  'a0000000-0000-4000-8000-0000001f0709',
  'a0000000-0000-4000-8000-0000001f0809',
  'a0000000-0000-4000-8000-0000001f0909',
  'a0000000-0000-4000-8000-0000001f1109'
);
